        expect(db.get('valid1')).toBe('value1');
        expect(db.get('valid2')).toBe('value2');
        // Should have emitted one error for the corrupted row
        expect(errors.length).toBe(1);
        expect(errors[0].message).toContain('corrupted_row');

        db.close();
        db.once('write_close', () => {
